function collect(rule, reasons, warnings) {
  const { name, check } = rule;
  if (check.status === "block") {
    reasons.push(`[${name}] ${check.reason}`);
  } else if (check.status === "warn") {
    warnings.push(`[${name}] ${check.reason}`);
  }
}
